  maokai: { diff: "EVEN", tone: "#e8b84b", tldr: "Out-combo him \u2014 dodge his root, snowball.", breakdown: "Dodge his W root, W-stun combo him, and snowball before he scales.", dos: ["Dodge his W root", "W-stun the combo", "Snowball before he scales"], donts: ["Get rooted into his combo", "Fight in saplings", "Waste E on poke"], key: { slot: "W", name: "Twisted Advance (Root)", cd: "11s", note: "His lock-on root. Dodge it.", winT: "ROOT DOWN", winS: "W-stun combo him." }, hold: "Hold E to dash out of his root combo.", tip: "E-dash to dodge his W root lock-on, then W-stun combo him \u2014 his tank kit can\u2019t answer your burst.", win: "Dodge his root and out-combo him." },
